from agent import *from models.products import *import simplejsonXCAT = ["JANUARY SALE", "Can Shop"]def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=4000)]    session.queue(Request("https://spiritstore.co.uk/"), process_frontpage, dict())def process_frontpage(data, context, session):    cats1 = data.xpath("//div[@class='menu-all-pages-container']/ul[1]/li")    for cat1 in cats1:        cat1_name = cat1.xpath("a//text()").string(multiple=True)        if cat1_name in XCAT:            continue        cats2 = cat1.xpath("div//div[@class='row']/ul/li")        for cat2 in cats2:            cat2_name = cat2.xpath("a//text()").string(multiple=True)            url = cat2.xpath("a/@href").string()            cats3 = cat2.xpath("div/ul/li")            if not cats3:                session.queue(Request(url), process_prodlist, dict(cat=cat1_name+'|'+cat2_name))            for cat3 in cats3:                cat3_name = cat3.xpath("a//text()").string(multiple=True)                url = cat3.xpath("a/@href").string()                session.queue(Request(url), process_prodlist, dict(cat=cat1_name+'|'+cat2_name+'|'+cat3_name))def process_prodlist(data, context, session):    prods = data.xpath("//ul[contains(@class, 'products-grid')]/li")    for prod in prods:        name = prod.xpath(".//h2[@class='product-name']/a/text()").string()        url = prod.xpath(".//h2[@class='product-name']/a/@href").string()        sku = prod.xpath(".//div/@data-sku").string()        session.queue(Request(url), process_product, dict(context, name=name, url=url, sku=sku))    next_page = data.xpath("//a[@title='Next']/@href").string()    if next_page:        session.queue(Request(next_page), process_prodlist, dict(context))def process_product(data, context, session):    product = Product()    product.name = context["name"]    product.url = context["url"]    product.sku = context["sku"].split(',')[0]    product.ssid = product.sku    product.category = context["cat"]    product.manufacturer = data.xpath("//th[text()='Brand']/following-sibling::td/text()").string()    sku = context["sku"].replace(',', "%2C")    revs_url = "https://widget.trustpilot.com/trustbox-data/5763bccae0a06d08e809ecbb?businessUnitId=5c069394390696000193aefe&locale=en-GB&sku=" + sku + "&reviewsPerPage=100&reviewLanguages=en"    session.do(Request(revs_url, use="curl"), process_reviews, dict(product=product))def process_reviews(data, context, session):    product = context['product']    json = simplejson.loads(data.content.replace("{}\r\n", ''))    revs = json["productReviews"]["reviews"]    for rev in revs:        review = Review()        review.type = 'user'        review.url = product.url        review.ssid = str(rev['id'])        review.date = rev['createdAt'].split('T')[0]        author_name = rev['consumer'].get('displayName', None)        if author_name:            review.authors.append(Person(name=author_name, ssid=author_name))        grade_overall = rev['stars']        if grade_overall:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        for grade in rev['attributes']:            value = rev['attributes'][grade]            review.grades.append(Grade(name=grade, value=float(value), best=5.0))        excerpt = rev.get('content')        if excerpt:            review.add_property(type='excerpt', value=excerpt.strip())            product.reviews.append(review)    next_url = json["productReviews"]["links"]["nextPage"]    if next_url:        session.do(Request(next_url, use="curl"), process_reviews, dict(context))    elif product.reviews:        session.emit(product)